<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('customers.manage');$id=(int)vp3_input('id');$stmt=vp3_db()->prepare('SELECT * FROM viewer_accounts WHERE id=? LIMIT 1');$stmt->execute([$id]);$viewerRow=$stmt->fetch();if(!$viewerRow){http_response_code(404);exit('Viewer not found.');}
if(vp3_method()==='POST'){vp3_verify_csrf();$status=vp3_input('status');if(!in_array($status,['active','suspended'],true))$status='suspended';vp3_db()->prepare('UPDATE viewer_accounts SET status=?,updated_at=NOW() WHERE id=?')->execute([$status,$id]);if($status==='suspended')vp3_db()->prepare('DELETE FROM viewer_remember_tokens WHERE viewer_id=?')->execute([$id]);vp3_audit('admin',(int)$admin['id'],'viewer.status_changed','viewer',(string)$viewerRow['viewer_uuid'],['status'=>$status]);vp3_flash('success','Viewer status updated.');vp3_redirect('admin/viewer.php?id='.$id);}
$pageTitle='Viewer: '.$viewerRow['display_name'];require VP3_ROOT.'/includes/admin-header.php';$counts=[];foreach(['likes'=>"SELECT COUNT(*) FROM viewer_clip_actions WHERE viewer_id=? AND action_type='like'",'saved'=>"SELECT COUNT(*) FROM viewer_clip_actions WHERE viewer_id=? AND action_type='save'",'history'=>'SELECT COUNT(*) FROM viewer_watch_history WHERE viewer_id=?','creator_follows'=>'SELECT COUNT(*) FROM viewer_creator_follows WHERE viewer_id=?','show_follows'=>'SELECT COUNT(*) FROM viewer_show_follows WHERE viewer_id=?']as$key=>$sql){$s=vp3_db()->prepare($sql);$s->execute([$id]);$counts[$key]=(int)$s->fetchColumn();}?>
<div class="admin-page-head"><div><span class="admin-kicker">Viewer account</span><h1><?=vp3_e($viewerRow['display_name'])?></h1><p>@<?=vp3_e($viewerRow['handle'])?> · <?=vp3_e($viewerRow['email'])?></p></div><a class="button secondary" href="viewers.php">Back to viewers</a></div><div class="stats"><div class="stat"><span>Likes</span><strong><?=$counts['likes']?></strong></div><div class="stat"><span>Saved</span><strong><?=$counts['saved']?></strong></div><div class="stat"><span>Watched</span><strong><?=$counts['history']?></strong></div><div class="stat"><span>Following</span><strong><?=$counts['creator_follows']+$counts['show_follows']?></strong></div></div><section class="card"><h2>Account control</h2><form method="post"><?=vp3_csrf_field()?><label>Status<select name="status"><option value="active" <?=$viewerRow['status']==='active'?'selected':''?>>Active</option><option value="suspended" <?=$viewerRow['status']==='suspended'?'selected':''?>>Suspended</option></select></label><button class="button">Update status</button></form><p class="helper">Suspending a viewer revokes remembered-device tokens. Password hashes and private tokens are never displayed.</p></section>
